mapper.select:
SELECT c.*, ste.site_nm AS site_nm, cd_scs.code_label AS close_status_cd_nm FROM st_settle_close c LEFT JOIN sy_site ste ON ste.site_id = c.site_id LEFT JOIN sy_code cd_scs ON cd_scs.code_grp = 'SETTLE_CLOSE_STATUS' AND cd_scs.code_value = c.close_status_cd
ORDER BY c.settle_close_id ASC ORDER BY c.settle_close_id DESC ORDER BY c.reg_date ASC ORDER BY c.reg_date DESC ORDER BY c.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

mapper.update:
UPDATE st_settle_close
settle_id = #{settleId}, site_id = #{siteId}, close_status_cd = #{closeStatusCd}, close_reason = #{closeReason}, final_settle_amt = #{finalSettleAmt}, close_by = #{closeBy}, close_date = #{closeDate},
WHERE settle_close_id = #{settleCloseId}
